const signs={beran:{name:"Beran",emoji:"\u2648",color:"#e74c3c",apiName:"Beran"},byk:{name:"Byk",emoji:"\u2649",color:"#27ae60",apiName:"B\xFDk"},blizenci:{name:"Bl\xED\u017Eenci",emoji:"\u264A",color:"#f39c12",apiName:"Bl\xED\u017Eenci"},rak:{name:"Rak",emoji:"\u264B",color:"#2980b9",apiName:"Rak"},lev:{name:"Lev",emoji:"\u264C",color:"#e67e22",apiName:"Lev"},panna:{name:"Panna",emoji:"\u264D",color:"#8e44ad",apiName:"Panna"},vahy:{name:"V\xE1hy",emoji:"\u264E",color:"#16a085",apiName:"V\xE1hy"},stir:{name:"\u0160t\xEDr",emoji:"\u264F",color:"#c0392b",apiName:"\u0160t\xEDr"},strelec:{name:"St\u0159elec",emoji:"\u2650",color:"#d35400",apiName:"St\u0159elec"},kozoroh:{name:"Kozoroh",emoji:"\u2651",color:"#7f8c8d",apiName:"Kozoroh"},vodnar:{name:"Vodn\xE1\u0159",emoji:"\u2652",color:"#2471a3",apiName:"Vodn\xE1\u0159"},ryby:{name:"Ryby",emoji:"\u2653",color:"#1a5276",apiName:"Ryby"}},moonPhases=[{name:"Nov \u2014 \u010Das nov\xFDch za\u010D\xE1tk\u016F",emoji:"\u{1F311}"},{name:"Dor\u016Fstaj\xEDc\xED srpek \u2014 \u010Das pl\xE1nov\xE1n\xED",emoji:"\u{1F312}"},{name:"Dor\u016Fstaj\xEDc\xED \u010Dtvr\u0165 \u2014 \u010Das akce",emoji:"\u{1F313}"},{name:"Dor\u016Fstaj\xEDc\xED m\u011Bs\xEDc \u2014 \u010Das expanze",emoji:"\u{1F314}"},{name:"\xDApln\u011Bk \u2014 \u010Das napln\u011Bn\xED",emoji:"\u{1F315}"},{name:"Couvaj\xEDc\xED m\u011Bs\xEDc \u2014 \u010Das vd\u011B\u010Dnosti",emoji:"\u{1F316}"},{name:"Ub\xFDvaj\xEDc\xED \u010Dtvr\u0165 \u2014 \u010Das reflexe",emoji:"\u{1F317}"},{name:"Ub\xFDvaj\xEDc\xED srpek \u2014 \u010Das uvoln\u011Bn\xED",emoji:"\u{1F318}"}];function getMoonPhase(){const o=(new Date-new Date("2000-01-06"))/(1e3*60*60*24),a=29.53,i=(o%a+a)%a;return moonPhases[Math.min(Math.floor(i/a*8),7)]}const fallbackAffirmations={beran:"M\xE1 odvaha tvo\u0159\xED mosty tam, kde ostatn\xED vid\xED propasti.",byk:"Jsem pevn\xFDm z\xE1kladem, ze kter\xE9ho roste v\u0161e kr\xE1sn\xE9 a trval\xE9.",blizenci:"M\xE1 zv\xEDdavost otv\xEDr\xE1 dve\u0159e, kter\xE9 jin\xED ani nevid\xED.",rak:"M\xE1 intuice je dnes nejjasn\u011Bj\u0161\xEDm sv\u011Btlem na m\xE9 cest\u011B.",lev:"Nesu v sob\u011B slunce \u2014 a dnes ho naplno sd\xEDl\xEDm se sv\u011Btem.",panna:"V ka\u017Ed\xE9m detailu nal\xE9z\xE1m kr\xE1su a smysl, kter\xFD ostatn\xED p\u0159ehl\xED\u017E\xED.",vahy:"P\u0159in\xE1\u0161\xEDm rovnov\xE1hu tam, kde ji sv\u011Bt nejv\xEDce pot\u0159ebuje.",stir:"Z ka\u017Ed\xE9 hloubky stoup\xE1m siln\u011Bj\u0161\xED \u2014 to je m\xE1 p\u0159irozenost.",strelec:"M\xE1 svoboda je m\xE1 s\xEDla \u2014 dnes ji naplno \u017Eiji a sd\xEDl\xEDm.",kozoroh:"Ka\u017Ed\xFD krok, kter\xFD d\u011Bl\xE1m, je investic\xED do m\xE9 budoucnosti.",vodnar:"M\xE1 originalita je dar sv\u011Btu \u2014 dnes ji p\u0159ij\xEDm\xE1m bez omluvy.",ryby:"Jsem oce\xE1nem soucitu \u2014 hlubok\xFD, klidn\xFD a nekone\u010Dn\xFD."};window.showAffirmation=async function(e){const n=signs[e];if(!n)return;document.querySelectorAll(".zodiac-btn").forEach(t=>t.classList.remove("active"));const o=document.querySelector(`.zodiac-btn[data-sign="${e}"]`);o&&o.classList.add("active");const a=document.getElementById("btn-horoskop-link");a&&(a.href=`horoskopy.html#${e}`);const i=getMoonPhase();document.getElementById("moon-badge").innerHTML=`${i.emoji} ${i.name}`,document.getElementById("sign-emoji").textContent=n.emoji,document.getElementById("sign-name").textContent=n.name.toUpperCase();const r=document.getElementById("affirmation-card");r.style.borderColor=n.color+"44",document.getElementById("affirmation-text").textContent="\u2728 Nalad\u011Bn\xED na energii va\u0161eho znamen\xED\u2026",document.getElementById("affirmation-sub").textContent="",r.classList.add("show"),r.scrollIntoView({behavior:"smooth",block:"nearest"});const c=`mh_aff_${e}_${new Date().toDateString()}`;try{const t=sessionStorage.getItem(c);if(t){const{text:m}=JSON.parse(t);document.getElementById("affirmation-text").textContent=`\u201E${m}"`,document.getElementById("affirmation-sub").textContent=i.name;try{localStorage.setItem("mh_last_affirmation_sign",e)}catch{}return}}catch{}try{const t=await window.callAPI("/horoscope",{sign:n.apiName,period:"daily"}),s=(typeof t.response=="string"?JSON.parse(t.response):t.response)?.affirmation;if(!s)throw new Error("No affirmation in response");document.getElementById("affirmation-text").textContent=`\u201E${s}"`,document.getElementById("affirmation-sub").textContent=i.name;try{sessionStorage.setItem(c,JSON.stringify({text:s}))}catch{}}catch(t){console.warn("[Afirmace] API fallback:",t.message);const m=fallbackAffirmations[e]||"Jsem v souladu se svou nejhlub\u0161\xED pravdou.";document.getElementById("affirmation-text").textContent=`\u201E${m}"`,document.getElementById("affirmation-sub").textContent=i.name}try{localStorage.setItem("mh_last_affirmation_sign",e)}catch{}};function copyAffirmation(){const n=document.getElementById("affirmation-text").textContent.replace(/^„|"$/g,"").trim();navigator.clipboard.writeText(n+" \u2014 Mystick\xE1 Hv\u011Bzda").then(()=>{const o=document.getElementById("copy-confirm");o.style.display="block",setTimeout(()=>o.style.display="none",2e3)})}function shareAffirmation(){const n=document.getElementById("affirmation-text").textContent.replace(/^„|"$/g,"").trim();navigator.share?navigator.share({title:"Moje dne\u0161n\xED afirmace",text:n,url:"https://mystickahvezda.cz/afirmace.html"}):copyAffirmation()}document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".zodiac-btn[data-sign]").forEach(e=>{e.addEventListener("click",()=>showAffirmation(e.dataset.sign))}),document.getElementById("btn-copy-affirmation").addEventListener("click",copyAffirmation),document.getElementById("btn-share-affirmation").addEventListener("click",shareAffirmation);try{const e=localStorage.getItem("mh_last_affirmation_sign");e&&signs[e]&&showAffirmation(e)}catch{}});
